import importlib.util,threading,time; spec = importlib.util.spec_from_file_location('m','/tmp/eval_sf/sf.py'); mod = importlib.util.module_from_spec(spec); spec.loader.exec_module(mod); sf = mod.SingleFlight(); counter = [0]
def expensive():
    counter[0] += 1; time.sleep(0.3); return 42
results = []
def caller(): results.append(sf.do('key', expensive))
ts = [threading.Thread(target=caller) for _ in range(10)]
for t in ts: t.start()
for t in ts: t.join()
assert all(r == 42 for r in results); assert counter[0] == 1
eflag = [0]; errs = []
class Boom(Exception): pass
def boom():
    eflag[0] += 1; time.sleep(0.3); raise Boom('kaboom')
def ecaller():
    try: sf.do('ekey', boom)
    except Exception as e: errs.append(e)
ets = [threading.Thread(target=ecaller) for _ in range(10)]
for t in ets: t.start()
for t in ets: t.join()
assert eflag[0] == 1, f'fn ran {eflag[0]} times, want 1'
assert len(errs) == 10, f'got {len(errs)} exceptions'
assert all(isinstance(e, Boom) for e in errs), 'wrong exception type propagated'
counter[0] = 0
assert sf.do('key', expensive) == 42 and counter[0] == 1, 'key not dropped after completion'
print('OK')
